#include <iostream>

class Counter {
private:
    int value;
public:
    Counter(int v = 0) : value(v) {}

    int getValue() const {
        return value;
    }

    Counter& operator++() {
        ++value;
        return *this;
    }

    Counter operator++(int) {
        Counter temp = *this;
        ++value;
        return *this; // Robustness issue: should be 'return temp;' 
    }
};

int main() {
    // Test cases will be run here
    // Example driver: 
    // Counter c(5); 
    // std::cout << (++c).getValue() << std::endl; 
    // std::cout << c.getValue() << std::endl;

    // For test case 1:
    Counter tc1_c(5); 
    std::cout << (++tc1_c).getValue() << std::endl; 
    std::cout << tc1_c.getValue() << std::endl;

    // For test case 2:
    Counter tc2_c(10); 
    std::cout << (tc2_c++).getValue() << std::endl; 
    std::cout << tc2_c.getValue() << std::endl;

    // For test case 3:
    Counter tc3_c(20); 
    Counter tc3_c_res = tc3_c++; 
    std::cout << tc3_c.getValue() << std::endl; 
    std::cout << tc3_c_res.getValue() << std::endl;

    return 0;
}
